        update_summary()
        
        # Filter function
        def apply_filters():
            try:
                selected_provider = self.provider_combo.currentText()
                start_date = self.start_date_edit.date().toPyDate()
                end_date = self.end_date_edit.date().toPyDate()
                
                if start_date > end_date:
                    QtWidgets.QMessageBox.warning(Dialog, "نطاق تاريخ غير صالح", "لا يمكن أن يكون تاريخ البداية بعد تاريخ النهاية")
                    return
                    
                filtered_data = []
                
                # First, collect all data that matches the provider filter
                provider_filtered_data = []
                if selected_provider == "جميع الموردين" or not selected_provider:
                    provider_filtered_data = data.copy()
                else:
                    provider_filtered_data = [item for item in data if str(item.get('provider', '')) == str(selected_provider)]
                
                # Now apply date filter
                for item in provider_filtered_data:
                    try:
                        timestamp = item.get('timestamp', '')
                        if not timestamp:
                            continue  # Skip if no timestamp
                            
                        # Parse the date from the timestamp
                        try:
                            item_date = datetime.datetime.strptime(timestamp, '%Y-%m-%d %H:%M:%S').date()
                        except ValueError:
                            # Try alternative format if the first one fails
                            item_date = datetime.datetime.strptime(timestamp, '%Y-%m-%d').date()
                            
                        if start_date <= item_date <= end_date:
                            filtered_data.append(item)
                    except Exception as e:
                        print(f"Error processing date '{timestamp}' for item: {e}")
                        continue
                
                # Clear and repopulate the table with filtered data
                table.setRowCount(0)
                for row, item in enumerate(filtered_data):
                    table.insertRow(row)
                    
                    # Get payment info
                    payment_info = safe_parse_payment_info(item.get('payment_info', '{}'))
                    payment_type = payment_info.get('type', 'cash').lower()
                    amount = float(item.get('amount', 0) or 0)
                    returned = float(item.get('amount_returned', 0) or 0)
                    net_amount = amount - returned
                    
                    # Set payment status and amounts based on payment type
                    if payment_type == 'partial':
                        amount_paid = f"{float(payment_info.get('amount_paid', 0)):.2f}"
                        net_owed = f"{float(payment_info.get('net_owed', net_amount)):.2f}"
                        payment_status = "دفع جزئي"
                    elif payment_type == 'debt':
                        amount_paid = "0.00"
                        net_owed = f"{net_amount:.2f}"
                        payment_status = "آجل"
                    else:  # cash
                        amount_paid = f"{net_amount:.2f}"
                        net_owed = "0.00"
                        payment_status = "مدفوع بالكامل"
                    
                    # Set items in table
                    table.setItem(row, 0, QtWidgets.QTableWidgetItem(item.get('provider', '')))
                    table.setItem(row, 1, QtWidgets.QTableWidgetItem(f"{amount:.2f}"))
                    table.setItem(row, 2, QtWidgets.QTableWidgetItem(item.get('doctor', '')))
                    table.setItem(row, 3, QtWidgets.QTableWidgetItem(f"{returned:.2f}"))
                    table.setItem(row, 4, QtWidgets.QTableWidgetItem(payment_status))
                    table.setItem(row, 5, QtWidgets.QTableWidgetItem(amount_paid))
                    table.setItem(row, 6, QtWidgets.QTableWidgetItem(net_owed))
                    table.setItem(row, 7, QtWidgets.QTableWidgetItem(item.get('order_code', '')))
                    table.setItem(row, 8, QtWidgets.QTableWidgetItem(item.get('timestamp', '')))
                    
                    # Set alignment for all cells
                    for col in range(table.columnCount()):
                        cell_item = table.item(row, col)
                        if cell_item:
                            cell_item.setTextAlignment(QtCore.Qt.AlignCenter | QtCore.Qt.AlignVCenter)
                            cell_item.setFlags(cell_item.flags() & ~QtCore.Qt.ItemIsEditable)
                
                # Update summary with filtered data
                update_summary(filtered_data)
                
            except Exception as e:
                print(f"Error in apply_filters: {e}")
                import traceback
                traceback.print_exc()
                payment_type = payment_info.get('type', 'cash').lower()
                amount = float(item.get('amount', 0) or 0)
                returned = float(item.get('amount_returned', 0) or 0)
                net_amount = amount - returned
                
                # Set payment status and amounts based on payment type
                if payment_type == 'partial':
                    amount_paid = f"{float(payment_info.get('amount_paid', 0)):.2f}"
                    net_owed = f"{float(payment_info.get('net_owed', net_amount)):.2f}"
                    payment_status = "دفع جزئي"
                elif payment_type == 'debt':
                    amount_paid = "0.00"
                    net_owed = f"{net_amount:.2f}"
                    payment_status = "آجل"
                else:  # cash
                    amount_paid = f"{net_amount:.2f}"
                    net_owed = "0.00"
                    payment_status = "مدفوع بالكامل"
                
                # Set items in table
                table.setItem(row, 0, QtWidgets.QTableWidgetItem(item.get('provider', '')))
                table.setItem(row, 1, QtWidgets.QTableWidgetItem(f"{amount:.2f}"))
                table.setItem(row, 2, QtWidgets.QTableWidgetItem(item.get('doctor', '')))
                table.setItem(row, 3, QtWidgets.QTableWidgetItem(f"{returned:.2f}"))
                table.setItem(row, 4, QtWidgets.QTableWidgetItem(payment_status))
                table.setItem(row, 5, QtWidgets.QTableWidgetItem(amount_paid))
                table.setItem(row, 6, QtWidgets.QTableWidgetItem(net_owed))
                table.setItem(row, 7, QtWidgets.QTableWidgetItem(item.get('order_code', '')))
                table.setItem(row, 8, QtWidgets.QTableWidgetItem(item.get('timestamp', '')))
                
                # Set alignment for all cells
