    import sys
    import traceback
    from PyQt5 import QtWidgets

    try:
        ensure_admin_exists()
        ensure_suppliers_exist()
        app = QtWidgets.QApplication(sys.argv)
        
        login = LoginDialog()
        if login.exec_() == QtWidgets.QDialog.Accepted and login.result:
            user = login.result
            
            # Check for updates on startup
            if UPDATER_AVAILABLE:
                try:
                    update_result = check_for_updates_on_startup()
                    if update_result and update_result.get('update_available'):
                        # Show update dialog if critical update or update available
                        if update_result.get('critical'):
                            show_update_dialog()
                        else:
                            # Show notification for non-critical updates
                            reply = QtWidgets.QMessageBox.question(
                                None,
                                "تحديث متوفر",
                                f"تحديث جديد متوفر: {update_result['latest_version']}\n\nهل تريد تثبيت التحديث الآن؟",
                                QtWidgets.QMessageBox.Yes | QtWidgets.QMessageBox.No
                            )
                            if reply == QtWidgets.QMessageBox.Yes:
                                show_update_dialog()
                except Exception as e:
                    print(f"Error checking for updates: {e}")
            
            Form = QtWidgets.QWidget()
            ui = Ui_Form(user)
            ui.setupUi(Form)
            Form.show()
            
            # Check license after main screen is shown but don't keep app open with dialog
            QtCore.QTimer.singleShot(500, lambda: check_and_enforce_license(Form, ui))
            
            sys.exit(app.exec_())
        else:
            sys.exit(0)
    except Exception as e:
        with open("app_error.log", "w") as f:
            f.write("Unhandled exception:\n")
            f.write(traceback.format_exc())
        print("An error occurred. Check app_error.log for details.")
        raise
